import type { OhlcvPoint } from '../../core/types';
import type { OverlayRenderPrimitive } from '../renderer';

export const WORKER_RENDER_SCHEMA_VERSION = 1 as const;
export const WORKER_HUD_OVERLAY_SCHEMA_VERSION = 1 as const;

export type WorkerHudOverlaySnapshotInput = Readonly<Partial<WorkerHudOverlaySnapshot>>;

export type WorkerHudOverlaySnapshot = Readonly<{
  version: number;
  markerCount: number;
  hlineCount: number;
  zoneCount: number;
  textCount: number;
  eventCount: number;
  totalCount: number;
  kindMask: number;
}>;

export function normalizeWorkerHudOverlaySnapshot(
  input: WorkerHudOverlaySnapshotInput | null | undefined,
): WorkerHudOverlaySnapshot | undefined {
  if (!input) return undefined;

  const markerCount = Number.isFinite(input.markerCount) ? Math.max(0, Math.floor(input.markerCount as number)) : 0;
  const hlineCount = Number.isFinite(input.hlineCount) ? Math.max(0, Math.floor(input.hlineCount as number)) : 0;
  const zoneCount = Number.isFinite(input.zoneCount) ? Math.max(0, Math.floor(input.zoneCount as number)) : 0;
  const textCount = Number.isFinite(input.textCount) ? Math.max(0, Math.floor(input.textCount as number)) : 0;
  const eventCount = Number.isFinite(input.eventCount) ? Math.max(0, Math.floor(input.eventCount as number)) : 0;

  let fallbackKindMask = 0;
  if (markerCount > 0) fallbackKindMask |= 1 << 0;
  if (hlineCount > 0) fallbackKindMask |= 1 << 1;
  if (zoneCount > 0) fallbackKindMask |= 1 << 2;
  if (textCount > 0) fallbackKindMask |= 1 << 3;
  if (eventCount > 0) fallbackKindMask |= 1 << 4;

  const totalFallback = markerCount + hlineCount + zoneCount + textCount + eventCount;
  const totalCount = Number.isFinite(input.totalCount) ? Math.max(0, Math.floor(input.totalCount as number)) : totalFallback;
  const kindMask = Number.isFinite(input.kindMask) ? Math.max(0, Math.floor(input.kindMask as number)) : fallbackKindMask;

  const version = Number.isFinite(input.version)
    ? Math.max(1, Math.floor(input.version as number))
    : WORKER_HUD_OVERLAY_SCHEMA_VERSION;

  return {
    version,
    markerCount,
    hlineCount,
    zoneCount,
    textCount,
    eventCount,
    totalCount,
    kindMask,
  };
}

export type ColumnarSliceData = {
  readonly time: Float64Array;
  readonly open: Float32Array;
  readonly high: Float32Array;
  readonly low: Float32Array;
  readonly close: Float32Array;
  readonly volume: Float32Array;
  readonly length: number;
};

export type WorkerRenderPayload = Readonly<{
  schemaVersion: number;
  viewport: Readonly<{
    startIndex: number;
    visibleCount: number;
    rightMarginBars: number;
  }>;
  layout: Readonly<{
    width: number;
    height: number;
    dpr: number;
  }>;
  hudOverlay?: WorkerHudOverlaySnapshot;
  data: ReadonlyArray<OhlcvPoint> | ColumnarSliceData;
}>;

export type WorkerOverlayPayload = Readonly<{
  clientX: number;
  clientY: number;
}>;

export type WorkerOverlayPrimitivePayload = Readonly<{
  revision: number;
  primitives: ReadonlyArray<OverlayRenderPrimitive>;
}>;

export type SharedFrameDescriptor = Readonly<{
  capacity: number;
  timeBuffer: SharedArrayBuffer;
  openBuffer: SharedArrayBuffer;
  highBuffer: SharedArrayBuffer;
  lowBuffer: SharedArrayBuffer;
  closeBuffer: SharedArrayBuffer;
  volumeBuffer: SharedArrayBuffer;
  controlBuffer: SharedArrayBuffer;
}>;

export type WorkerSharedRenderPayload = Readonly<{
  schemaVersion: number;
  viewport: Readonly<{
    startIndex: number;
    visibleCount: number;
    rightMarginBars: number;
  }>;
  layout: Readonly<{
    width: number;
    height: number;
    dpr: number;
  }>;
  hudOverlay?: WorkerHudOverlaySnapshot;
  frameId: number;
}>;

export type WorkerMessageToRender =
  | { type: 'init'; chartId: number; canvas: OffscreenCanvas }
  | { type: 'initShared'; chartId: number; descriptor: SharedFrameDescriptor }
  | { type: 'render'; chartId: number; payload: WorkerRenderPayload }
  | { type: 'renderShared'; chartId: number; payload: WorkerSharedRenderPayload }
  | { type: 'ann_bulk'; chartId: number; payload: WorkerOverlayPrimitivePayload }
  | { type: 'ann_clear'; chartId: number }
  | { type: 'overlay'; chartId: number; payload: WorkerOverlayPayload }
  | { type: 'clearOverlay'; chartId: number }
  | { type: 'destroy'; chartId: number };
