import {
  computePaddedPriceRange,
  computeRendererLayout,
} from '../candleLayout';
import type { OhlcvPoint } from '../../core/types';
import type {
  WorkerMessageToRender,
  WorkerRenderPayload,
  WorkerOverlayPayload,
  WorkerSharedRenderPayload,
  ColumnarSliceData,
} from './protocol';
import {
  WORKER_RENDER_SCHEMA_VERSION,
  normalizeWorkerHudOverlaySnapshot,
} from './protocol';
import { createSharedViews } from './sharedFrameBuffer';
import type { ColumnarSlice } from '../../data/columnarStore';
import { preprocessCandleGeometry } from './geometryPreprocess';
import { drawCrosshairOverlay } from '../overlay/crosshairOverlay';
import { drawHudTag, drawXAxisTicksAndLabels, drawYAxisGridAndLabels } from '../overlay/displayPrimitives';
import type { OverlayRenderPrimitive } from '../renderer';

let canvas: OffscreenCanvas | null = null;
let ctx: OffscreenCanvasRenderingContext2D | null = null;
let lastPayload: WorkerRenderPayload | null = null;
let lastSharedPayload: WorkerSharedRenderPayload | null = null;
let sharedViews: ReturnType<typeof createSharedViews> | null = null;
let currentDpr = 1;
let rafId: number | null = null;
let pendingOverlay: WorkerOverlayPayload | null = null;
let overlayPrimitiveRevision = -1;
let overlayPrimitives: ReadonlyArray<OverlayRenderPrimitive> = [];
let currentChartId = -1;

type HudSummaryCache = { key: string; text: string };

type ChartWorkerState = {
  canvas: OffscreenCanvas | null;
  ctx: OffscreenCanvasRenderingContext2D | null;
  lastPayload: WorkerRenderPayload | null;
  lastSharedPayload: WorkerSharedRenderPayload | null;
  sharedViews: ReturnType<typeof createSharedViews> | null;
  currentDpr: number;
  rafId: number | null;
  pendingOverlay: WorkerOverlayPayload | null;
  overlayPrimitiveRevision: number;
  overlayPrimitives: ReadonlyArray<OverlayRenderPrimitive>;
  hudSummaryCache: HudSummaryCache;
};

const chartStates = new Map<number, ChartWorkerState>();

function makeChartState(): ChartWorkerState {
  return {
    canvas: null,
    ctx: null,
    lastPayload: null,
    lastSharedPayload: null,
    sharedViews: null,
    currentDpr: 1,
    rafId: null,
    pendingOverlay: null,
    overlayPrimitiveRevision: -1,
    overlayPrimitives: [],
    hudSummaryCache: { key: '', text: '' },
  };
}

function activateChartState(chartId: number): ChartWorkerState {
  let state = chartStates.get(chartId);
  if (!state) {
    state = makeChartState();
    chartStates.set(chartId, state);
  }

  currentChartId = chartId;
  canvas = state.canvas;
  ctx = state.ctx;
  lastPayload = state.lastPayload;
  lastSharedPayload = state.lastSharedPayload;
  sharedViews = state.sharedViews;
  currentDpr = state.currentDpr;
  rafId = state.rafId;
  pendingOverlay = state.pendingOverlay;
  overlayPrimitiveRevision = state.overlayPrimitiveRevision;
  overlayPrimitives = state.overlayPrimitives;
  hudSummaryCache = state.hudSummaryCache;
  return state;
}

function persistActiveChartState(): void {
  if (currentChartId < 0) return;
  const state = chartStates.get(currentChartId);
  if (!state) return;
  state.canvas = canvas;
  state.ctx = ctx;
  state.lastPayload = lastPayload;
  state.lastSharedPayload = lastSharedPayload;
  state.sharedViews = sharedViews;
  state.currentDpr = currentDpr;
  state.rafId = rafId;
  state.pendingOverlay = pendingOverlay;
  state.overlayPrimitiveRevision = overlayPrimitiveRevision;
  state.overlayPrimitives = overlayPrimitives;
  state.hudSummaryCache = hudSummaryCache;
}

const BACKGROUND = '#ffffff';
const UP = '#00b359';
const DOWN = '#d93636';
const WICK = '#2a2a2a';
const AXIS = '#222222';
const GRID = '#e6e6e6';
const HUD_SUMMARY_BG = 'rgba(0,0,0,0.64)';
const WATERMARK_TEXT = 'Mochart alpha - not for redistribution';
const EMPTY_DASH: number[] = [];

function resolveTimeToX(
  time: number,
  firstTime: number,
  spanMs: number,
  plotX: number,
  plotW: number,
): number {
  const t = spanMs > 0 ? (time - firstTime) / spanMs : 0;
  const clamped = Math.max(0, Math.min(1, t));
  return plotX + clamped * plotW;
}

function resolvePriceToY(price: number, yMin: number, yMax: number, plotY: number, plotH: number): number {
  const den = Math.max(1e-6, yMax - yMin);
  const t = (price - yMin) / den;
  const clamped = Math.max(0, Math.min(1, t));
  return plotY + (1 - clamped) * plotH;
}

function drawOverlayPrimitives(
  renderCtx: OffscreenCanvasRenderingContext2D,
  primitives: ReadonlyArray<OverlayRenderPrimitive>,
  firstTime: number,
  spanMs: number,
  yMin: number,
  yMax: number,
  plotX: number,
  plotY: number,
  plotW: number,
  plotH: number,
): void {
  if (primitives.length === 0) return;

  for (let i = 0; i < primitives.length; i++) {
    const p = primitives[i];
    if (p.type === 'zone') {
      const x1 = resolveTimeToX(p.time, firstTime, spanMs, plotX, plotW);
      const x2 = resolveTimeToX(p.timeEnd, firstTime, spanMs, plotX, plotW);
      const y1 = resolvePriceToY(p.priceEnd ?? yMax, yMin, yMax, plotY, plotH);
      const y2 = resolvePriceToY(p.price ?? yMin, yMin, yMax, plotY, plotH);
      renderCtx.fillStyle = p.colorCss ?? 'rgba(80,80,80,0.14)';
      renderCtx.fillRect(Math.min(x1, x2), Math.min(y1, y2), Math.abs(x2 - x1), Math.max(1, Math.abs(y2 - y1)));
      continue;
    }

    if (p.type === 'hline') {
      const lx1 = p.time != null ? resolveTimeToX(p.time, firstTime, spanMs, plotX, plotW) : plotX;
      const lx2 = p.timeEnd != null ? resolveTimeToX(p.timeEnd, firstTime, spanMs, plotX, plotW) : (plotX + plotW);
      const ly = resolvePriceToY(p.price, yMin, yMax, plotY, plotH);
      renderCtx.strokeStyle = p.colorCss ?? 'rgba(40,40,40,0.8)';
      renderCtx.lineWidth = 1;
      if (p.dash && p.dash.length > 0) {
        renderCtx.setLineDash(p.dash as number[]);
      } else {
        renderCtx.setLineDash(EMPTY_DASH);
      }
      renderCtx.beginPath();
      renderCtx.moveTo(lx1, ly);
      renderCtx.lineTo(lx2, ly);
      renderCtx.stroke();
      renderCtx.setLineDash(EMPTY_DASH);
      continue;
    }

    if (p.type === 'marker') {
      const mx = resolveTimeToX(p.time, firstTime, spanMs, plotX, plotW);
      const my = resolvePriceToY(p.price, yMin, yMax, plotY, plotH);
      renderCtx.strokeStyle = p.colorCss ?? 'rgba(20,20,20,0.9)';
      renderCtx.fillStyle = p.colorCss ?? 'rgba(20,20,20,0.9)';
      renderCtx.lineWidth = 1;
      if (p.shape === 'arrow_down') {
        renderCtx.beginPath();
        renderCtx.moveTo(mx, my + 5);
        renderCtx.lineTo(mx - 4, my - 3);
        renderCtx.lineTo(mx + 4, my - 3);
        renderCtx.closePath();
        renderCtx.fill();
      } else {
        renderCtx.beginPath();
        renderCtx.moveTo(mx, my - 5);
        renderCtx.lineTo(mx - 4, my + 3);
        renderCtx.lineTo(mx + 4, my + 3);
        renderCtx.closePath();
        renderCtx.fill();
      }
    }
  }
}

let hudSummaryCache = {
  key: '',
  text: '',
};

const DATE_FORMATTER_SHORT = new Intl.DateTimeFormat(undefined, { month: 'short', day: 'numeric' });
const DATE_FORMATTER_FULL = new Intl.DateTimeFormat(undefined);

function assertNeverMessage(x: never): never {
  throw new Error(`Unexpected worker message: ${(x as { type: string }).type}`);
}

function formatPrice(value: number): string {
  const abs = Math.abs(value);
  const digits = abs < 1 ? 4 : abs < 10 ? 3 : 2;
  return value.toFixed(digits);
}

function formatDateLabel(time: number, spanMs: number): string {
  return spanMs > 365 * 24 * 3600 * 1000
    ? DATE_FORMATTER_FULL.format(new Date(time))
    : DATE_FORMATTER_SHORT.format(new Date(time));
}

function formatHudSummary(hud: WorkerRenderPayload['hudOverlay'] | WorkerSharedRenderPayload['hudOverlay']): string {
  if (!hud) return '';
  const total = hud.totalCount;
  if (total <= 0) return '';

  const key = `${hud.totalCount}|${hud.kindMask}|${hud.markerCount}|${hud.hlineCount}|${hud.zoneCount}|${hud.textCount}|${hud.eventCount}`;
  if (hudSummaryCache.key === key) return hudSummaryCache.text;

  hudSummaryCache.key = key;
  hudSummaryCache.text = `ANN ${total} M${hud.markerCount} H${hud.hlineCount} Z${hud.zoneCount} T${hud.textCount} E${hud.eventCount}`;
  return hudSummaryCache.text;
}

function normalizeRenderPayload(payload: WorkerRenderPayload): WorkerRenderPayload {
  const schemaVersion = Number.isFinite(payload.schemaVersion)
    ? Math.max(1, Math.floor(payload.schemaVersion))
    : WORKER_RENDER_SCHEMA_VERSION;
  return {
    ...payload,
    schemaVersion,
    hudOverlay: normalizeWorkerHudOverlaySnapshot(payload.hudOverlay),
  };
}

function normalizeSharedRenderPayload(payload: WorkerSharedRenderPayload): WorkerSharedRenderPayload {
  const schemaVersion = Number.isFinite(payload.schemaVersion)
    ? Math.max(1, Math.floor(payload.schemaVersion))
    : WORKER_RENDER_SCHEMA_VERSION;
  return {
    ...payload,
    schemaVersion,
    hudOverlay: normalizeWorkerHudOverlaySnapshot(payload.hudOverlay),
  };
}

function drawHudSummaryTag(
  renderCtx: OffscreenCanvasRenderingContext2D,
  plotX: number,
  plotY: number,
  plotW: number,
  hud: WorkerRenderPayload['hudOverlay'] | WorkerSharedRenderPayload['hudOverlay'],
): void {
  const text = formatHudSummary(hud);
  if (!text) return;
  drawHudTag(renderCtx, {
    anchorX: plotX + plotW - 6,
    centerY: plotY + 10,
    text,
    backgroundColor: HUD_SUMMARY_BG,
    textColor: '#ffffff',
    font: '10px monospace',
    paddingX: 4,
    height: 14,
  });
}

function drawWatermark(
  renderCtx: OffscreenCanvasRenderingContext2D,
  width: number,
  height: number,
): void {
  const cx = width * 0.5;
  const cy = height * 0.5;
  renderCtx.save();
  renderCtx.translate(cx, cy);
  renderCtx.rotate(-Math.PI / 6);
  renderCtx.textAlign = 'center';
  renderCtx.textBaseline = 'middle';
  renderCtx.font = '600 18px sans-serif';
  renderCtx.fillStyle = 'rgba(24,24,24,0.14)';
  renderCtx.fillText(WATERMARK_TEXT, 0, 0);
  renderCtx.restore();
}

function renderCrosshair(payload: WorkerOverlayPayload): void {
  if (!ctx || !canvas) return;
  const width = canvas.width / Math.max(1, currentDpr);
  const height = canvas.height / Math.max(1, currentDpr);

  drawCrosshairOverlay(ctx, {
    plotX: 0,
    plotY: 0,
    plotW: width,
    plotH: height,
    x: payload.clientX,
    clampedY: payload.clientY,
    priceAtY: payload.clientY,
    strokeColor: 'rgba(0,0,0,0.45)',
    lineWidth: 1,
    labelText: '',
  });
}

function waitForSharedFrame(targetFrameId: number): void {
  if (!sharedViews) return;
  const control = sharedViews.control;
  let current = Atomics.load(control, 0);
  if (current >= targetFrameId) return;

  if (typeof Atomics.wait === 'function') {
    while (current < targetFrameId) {
      Atomics.wait(control, 0, current, 1);
      current = Atomics.load(control, 0);
    }
    return;
  }

  while (current < targetFrameId) {
    current = Atomics.load(control, 0);
  }
}

function isColumnarData(data: ReadonlyArray<OhlcvPoint> | ColumnarSliceData): data is ColumnarSliceData {
  return (data as ColumnarSliceData).time instanceof Float64Array;
}

function renderFrame(payload: WorkerRenderPayload): void {
  if (!ctx || !canvas) return;

  const width = Math.max(1, Math.floor(payload.layout.width));
  const height = Math.max(1, Math.floor(payload.layout.height));
  const dpr = payload.layout.dpr || 1;
  currentDpr = dpr;

  const targetWidth = Math.max(1, Math.floor(width * dpr));
  const targetHeight = Math.max(1, Math.floor(height * dpr));
  if (canvas.width !== targetWidth || canvas.height !== targetHeight) {
    canvas.width = targetWidth;
    canvas.height = targetHeight;
  }

  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, width, height);
  ctx.fillStyle = BACKGROUND;
  ctx.fillRect(0, 0, width, height);
  const layout = computeRendererLayout(width, height);
  const { plotX, plotY, plotW, plotH } = layout;

  const data = payload.data;
  const isColumnar = isColumnarData(data);
  const dataLen = isColumnar ? (data as ColumnarSliceData).length : (data as ReadonlyArray<OhlcvPoint>).length;

  if (dataLen === 0) {
    lastPayload = payload;
    return;
  }

  const start = Math.max(0, Math.floor(payload.viewport.startIndex));
  const startFraction = Math.max(0, payload.viewport.startIndex - start);
  const visibleCount = Math.max(1, Math.floor(payload.viewport.visibleCount));
  const end = Math.min(dataLen, start + visibleCount + 1);
  if (start >= end) {
    lastPayload = payload;
    return;
  }

  // Helper to access data regardless of shape
  const cData = isColumnar ? (data as ColumnarSliceData) : null;
  const aData = !isColumnar ? (data as ReadonlyArray<OhlcvPoint>) : null;

  const geometry = preprocessCandleGeometry({
    count: end - start,
    width: plotW,
    height: plotH,
    visibleCount,
    startFraction,
    rightMarginBars: payload.viewport.rightMarginBars,
    getOpen: isColumnar ? (i) => cData!.open[start + i] : (i) => aData![start + i].open,
    getHigh: isColumnar ? (i) => cData!.high[start + i] : (i) => aData![start + i].high,
    getLow: isColumnar ? (i) => cData!.low[start + i] : (i) => aData![start + i].low,
    getClose: isColumnar ? (i) => cData!.close[start + i] : (i) => aData![start + i].close,
  });

  const priceRange = computePaddedPriceRange(geometry.min, geometry.max, plotH);
  const yMin = priceRange.min;
  const yMax = priceRange.max;

  drawYAxisGridAndLabels(ctx, {
    plotX,
    plotY,
    plotW,
    plotH,
    yMin,
    yMax,
    targetYTicks: 5,
    font: '12px sans-serif',
    axisColor: AXIS,
    gridColor: GRID,
    formatPrice,
  });

  // Safe access for time with boundary checks
  const getTime = (index: number) => {
    const safeIndex = Math.max(0, Math.min(dataLen - 1, index));
    return isColumnar ? cData!.time[safeIndex] : aData![safeIndex].time;
  };

  const firstTime = getTime(start);
  const lastTime = getTime(Math.max(start, end - 1));
  const spanMs = Math.max(1, lastTime - firstTime);

  drawOverlayPrimitives(ctx, overlayPrimitives, firstTime, spanMs, yMin, yMax, plotX, plotY, plotW, plotH);
  
  drawXAxisTicksAndLabels(ctx, {
    plotX,
    plotY,
    plotW,
    plotH,
    stepX: geometry.stepX,
    visibleCount,
    targetXTicks: 6,
    font: '12px sans-serif',
    axisColor: AXIS,
    getLabelAtLocalIndex: (localIdx) => {
      const totalLen = isColumnar ? cData!.length : aData!.length;
      const idx = Math.max(0, Math.min(totalLen - 1, start + localIdx));
      return formatDateLabel(isColumnar ? cData!.time[idx] : aData![idx].time, spanMs);
    },
  });

  ctx.save();
  ctx.beginPath();
  ctx.rect(plotX, plotY, plotW, plotH);
  ctx.clip();

  for (let i = 0; i < geometry.count; i++) {
    const offset = i * 6;
    const xCenter = plotX + geometry.buffer[offset + 0];
    const yOpen = plotY + geometry.buffer[offset + 1];
    const yClose = plotY + geometry.buffer[offset + 2];
    const yHigh = plotY + geometry.buffer[offset + 3];
    const yLow = plotY + geometry.buffer[offset + 4];
    const isUp = geometry.buffer[offset + 5] === 1;
    const bodyTop = Math.min(yOpen, yClose);
    const bodyBottom = Math.max(yOpen, yClose);
    const bodyH = Math.max(1, bodyBottom - bodyTop);

    ctx.fillStyle = WICK;
    ctx.fillRect(xCenter - geometry.wickWidth * 0.5, yHigh, geometry.wickWidth, Math.max(1, yLow - yHigh));

    ctx.fillStyle = isUp ? UP : DOWN;
    ctx.fillRect(xCenter - geometry.bodyWidth * 0.5, bodyTop, geometry.bodyWidth, bodyH);
  }
  ctx.restore();
  drawHudSummaryTag(ctx, plotX, plotY, plotW, payload.hudOverlay);
  drawWatermark(ctx, width, height);
  lastPayload = payload;

  try {
    (self as any).postMessage?.({ type: 'frameDone', chartId: currentChartId });
  } catch {
    // ignore
  }
}

function renderSharedFrame(payload: WorkerSharedRenderPayload): void {
  if (!ctx || !canvas || !sharedViews) return;
  const views = sharedViews;

  waitForSharedFrame(payload.frameId);

  const width = Math.max(1, Math.floor(payload.layout.width));
  const height = Math.max(1, Math.floor(payload.layout.height));
  const dpr = payload.layout.dpr || 1;
  currentDpr = dpr;

  const targetWidth = Math.max(1, Math.floor(width * dpr));
  const targetHeight = Math.max(1, Math.floor(height * dpr));
  if (canvas.width !== targetWidth || canvas.height !== targetHeight) {
    canvas.width = targetWidth;
    canvas.height = targetHeight;
  }

  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
  ctx.clearRect(0, 0, width, height);
  ctx.fillStyle = BACKGROUND;
  ctx.fillRect(0, 0, width, height);

  const layout = computeRendererLayout(width, height);
  const { plotX, plotY, plotW, plotH } = layout;

  const visibleCount = Math.max(1, Math.floor(payload.viewport.visibleCount));
  const visibleCountActual = Math.max(0, Atomics.load(views.control, 2));
  if (visibleCountActual === 0) {
    lastSharedPayload = payload;
    return;
  }

  const startFloor = Math.max(0, Math.floor(payload.viewport.startIndex));
  const startFraction = Math.max(0, payload.viewport.startIndex - startFloor);

  const geometry = preprocessCandleGeometry({
    count: visibleCountActual,
    width: plotW,
    height: plotH,
    visibleCount,
    startFraction,
    rightMarginBars: payload.viewport.rightMarginBars,
    getOpen: (i) => views.open[i],
    getHigh: (i) => views.high[i],
    getLow: (i) => views.low[i],
    getClose: (i) => views.close[i],
  });

  const priceRange = computePaddedPriceRange(geometry.min, geometry.max, plotH);
  const yMin = priceRange.min;
  const yMax = priceRange.max;

  drawYAxisGridAndLabels(ctx, {
    plotX,
    plotY,
    plotW,
    plotH,
    yMin,
    yMax,
    targetYTicks: 5,
    font: '12px sans-serif',
    axisColor: AXIS,
    gridColor: GRID,
    formatPrice,
  });

  const firstTime = views.time[0] ?? 0;
  const lastTime = views.time[Math.max(0, visibleCountActual - 1)] ?? firstTime;
  const spanMs = Math.max(1, lastTime - firstTime);
  drawXAxisTicksAndLabels(ctx, {
    plotX,
    plotY,
    plotW,
    plotH,
    stepX: geometry.stepX,
    visibleCount,
    targetXTicks: 6,
    font: '12px sans-serif',
    axisColor: AXIS,
    getLabelAtLocalIndex: (localIdx) => {
      const source = localIdx - Math.floor(startFraction);
      const idx = Math.max(0, Math.min(visibleCountActual - 1, source));
      return formatDateLabel(views.time[idx] ?? firstTime, spanMs);
    },
  });

  ctx.save();
  ctx.beginPath();
  ctx.rect(plotX, plotY, plotW, plotH);
  ctx.clip();
  for (let i = 0; i < geometry.count; i++) {
    const offset = i * 6;
    const xCenter = plotX + geometry.buffer[offset + 0];
    const yOpen = plotY + geometry.buffer[offset + 1];
    const yClose = plotY + geometry.buffer[offset + 2];
    const yHigh = plotY + geometry.buffer[offset + 3];
    const yLow = plotY + geometry.buffer[offset + 4];
    const isUp = geometry.buffer[offset + 5] === 1;
    const bodyTop = Math.min(yOpen, yClose);
    const bodyBottom = Math.max(yOpen, yClose);
    const bodyH = Math.max(1, bodyBottom - bodyTop);

    ctx.fillStyle = WICK;
    ctx.fillRect(xCenter - geometry.wickWidth * 0.5, yHigh, geometry.wickWidth, Math.max(1, yLow - yHigh));

    ctx.fillStyle = isUp ? UP : DOWN;
    ctx.fillRect(xCenter - geometry.bodyWidth * 0.5, bodyTop, geometry.bodyWidth, bodyH);
  }
  ctx.restore();
  drawHudSummaryTag(ctx, plotX, plotY, plotW, payload.hudOverlay);
  drawWatermark(ctx, width, height);

  lastSharedPayload = payload;
  // Notify main thread that this frame has been rendered.
  try {
    // worker -> main notification
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (self as any).postMessage?.({ type: 'frameDone', chartId: currentChartId });
  } catch {
    // ignore
  }
}

function scheduleRender(chartId: number): void {
  const state = activateChartState(chartId);
  if (state.rafId !== null) {
    persistActiveChartState();
    return;
  }

  const cb = () => {
    activateChartState(chartId);
    rafId = null;
    if (lastPayload) {
      renderFrame(lastPayload);
    } else if (lastSharedPayload) {
      renderSharedFrame(lastSharedPayload);
    }

    if (pendingOverlay) {
      renderCrosshair(pendingOverlay);
      pendingOverlay = null;
    }
    persistActiveChartState();
  };

  if (typeof requestAnimationFrame === 'function') {
    rafId = requestAnimationFrame(cb) as unknown as number;
  } else {
    rafId = setTimeout(cb, 16) as unknown as number;
  }
  persistActiveChartState();
}

self.onmessage = (event: MessageEvent<WorkerMessageToRender>) => {
  const msg = event.data;
  activateChartState(msg.chartId);

  switch (msg.type) {
    case 'init': {
      canvas = msg.canvas;
      ctx = canvas.getContext('2d');
      break;
    }
    case 'initShared': {
      sharedViews = createSharedViews(msg.descriptor);
      break;
    }
    case 'render': {
      lastPayload = normalizeRenderPayload(msg.payload);
      persistActiveChartState();
      scheduleRender(msg.chartId);
      return;
    }
    case 'renderShared': {
      lastSharedPayload = normalizeSharedRenderPayload(msg.payload);
      persistActiveChartState();
      scheduleRender(msg.chartId);
      return;
    }
    case 'ann_bulk': {
      if (msg.payload.revision >= overlayPrimitiveRevision) {
        overlayPrimitiveRevision = msg.payload.revision;
        overlayPrimitives = msg.payload.primitives;
      }
      break;
    }
    case 'ann_clear': {
      overlayPrimitiveRevision = -1;
      overlayPrimitives = [];
      persistActiveChartState();
      scheduleRender(msg.chartId);
      return;
    }
    case 'overlay': {
      pendingOverlay = msg.payload;
      persistActiveChartState();
      scheduleRender(msg.chartId);
      return;
    }
    case 'clearOverlay': {
      pendingOverlay = null;
      persistActiveChartState();
      scheduleRender(msg.chartId);
      return;
    }
    case 'destroy': {
      if (rafId !== null) {
        if (typeof cancelAnimationFrame === 'function') cancelAnimationFrame(rafId as unknown as number);
        else clearTimeout(rafId as unknown as number);
      }
      chartStates.delete(msg.chartId);
      currentChartId = -1;
      return;
    }
    default:
      assertNeverMessage(msg);
  }

  persistActiveChartState();
};
