export type CanvasLike2D = CanvasRenderingContext2D | OffscreenCanvasRenderingContext2D;

export interface AxisYGridParams {
  plotX: number;
  plotY: number;
  plotW: number;
  plotH: number;
  yMin: number;
  yMax: number;
  targetYTicks?: number;
  font?: string;
  axisColor: string;
  gridColor: string;
  formatPrice: (value: number) => string;
}

export interface AxisXLabelParams {
  plotX: number;
  plotY: number;
  plotW: number;
  plotH: number;
  stepX: number;
  visibleCount: number;
  targetXTicks?: number;
  font?: string;
  axisColor: string;
  getLabelAtLocalIndex: (localIndex: number) => string;
}

export interface HudTagParams {
  anchorX: number;
  centerY: number;
  text: string;
  backgroundColor: string;
  textColor?: string;
  font?: string;
  paddingX?: number;
  height?: number;
}

function computeNiceStep(range: number, targetTicks: number): number {
  const safeRange = Math.max(range, 1e-9);
  const raw = safeRange / Math.max(1, targetTicks);
  const pow = Math.pow(10, Math.floor(Math.log10(raw)));
  const r = raw / pow;
  const nice = r <= 1 ? 1 : r <= 2 ? 2 : r <= 5 ? 5 : 10;
  return nice * pow;
}

export function drawYAxisGridAndLabels(ctx: CanvasLike2D, params: AxisYGridParams): void {
  const {
    plotX,
    plotY,
    plotW,
    plotH,
    yMin,
    yMax,
    axisColor,
    gridColor,
    formatPrice,
  } = params;
  const targetYTicks = params.targetYTicks ?? 5;

  const priceToY = (price: number) => {
    const t = (price - yMin) / (yMax - yMin || 1);
    return plotY + (1 - t) * plotH;
  };

  const step = computeNiceStep(yMax - yMin, targetYTicks);
  const firstTick = Math.ceil(yMin / step) * step;

  ctx.font = params.font ?? '12px sans-serif';
  ctx.textAlign = 'right';
  ctx.textBaseline = 'middle';
  ctx.lineWidth = 1;
  ctx.strokeStyle = gridColor;
  ctx.fillStyle = axisColor;

  for (let tick = firstTick; tick <= yMax + 1e-12; tick += step) {
    const y = priceToY(tick);
    ctx.beginPath();
    ctx.moveTo(plotX, y);
    ctx.lineTo(plotX + plotW, y);
    ctx.stroke();
    ctx.fillText(formatPrice(tick), plotX - 8, y);
  }

  ctx.strokeStyle = axisColor;
  ctx.beginPath();
  ctx.moveTo(plotX, plotY);
  ctx.lineTo(plotX, plotY + plotH);
  ctx.stroke();
}

export function drawXAxisTicksAndLabels(ctx: CanvasLike2D, params: AxisXLabelParams): void {
  const {
    plotX,
    plotY,
    plotW,
    plotH,
    stepX,
    visibleCount,
    axisColor,
    getLabelAtLocalIndex,
  } = params;
  const targetXTicks = params.targetXTicks ?? 6;

  ctx.fillStyle = axisColor;
  ctx.font = params.font ?? '12px sans-serif';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'top';
  ctx.strokeStyle = axisColor;
  ctx.lineWidth = 1;

  for (let i = 0; i < targetXTicks; i++) {
    const frac = targetXTicks <= 1 ? 0 : i / (targetXTicks - 1);
    const localIdx = Math.round(frac * Math.max(0, visibleCount - 1));
    const x = plotX + localIdx * stepX;
    ctx.beginPath();
    ctx.moveTo(x + 0.5, plotY + plotH);
    ctx.lineTo(x + 0.5, plotY + plotH + 6);
    ctx.stroke();
    ctx.fillText(getLabelAtLocalIndex(localIdx), x, plotY + plotH + 6);
  }

  ctx.beginPath();
  ctx.moveTo(plotX, plotY + plotH);
  ctx.lineTo(plotX + plotW, plotY + plotH);
  ctx.stroke();
}

export function drawHudTag(ctx: CanvasLike2D, params: HudTagParams): void {
  const paddingX = params.paddingX ?? 4;
  const tagHeight = params.height ?? 16;
  const textColor = params.textColor ?? '#ffffff';

  ctx.font = params.font ?? '11px sans-serif';
  ctx.textAlign = 'right';
  ctx.textBaseline = 'middle';
  const textWidth = ctx.measureText(params.text).width;
  const tagWidth = textWidth + paddingX * 2;

  ctx.fillStyle = params.backgroundColor;
  ctx.fillRect(params.anchorX - tagWidth, params.centerY - tagHeight / 2, tagWidth, tagHeight);
  ctx.fillStyle = textColor;
  ctx.fillText(params.text, params.anchorX - paddingX, params.centerY);
}
